sql:
SELECT datasets.dataset_name, documentation.doc_type, documentation.doc_link
FROM datasets
JOIN documentation ON datasets.dataset_id = documentation.dataset_id;

SELECT climo_type 
FROM climo_data 
WHERE climo_type IN ('midpoint', 'median');

SELECT dataset_id, COUNT(access_id) / COUNT(DISTINCT access_date) AS avg_access_frequency 
FROM access_logs 
GROUP BY dataset_id;

SELECT guide_name
FROM guides
WHERE dataset_id = 0;

SELECT variable_name
FROM variables
WHERE variable_id = 1;

SELECT relationship
FROM dataset_sources
WHERE dataset_id = 1;

SELECT dataset_name, description 
FROM datasets 
WHERE variables LIKE '%temperature%';

SELECT datasets.dataset_name, guides.guide_name, guides.guide_link
FROM datasets
INNER JOIN guides ON datasets.dataset_id = guides.dataset_id;

external_knowledge:
'early to late part of the latter half of the 20th century' refers to the period between 1981 and 2010;
'night temperature readings' refers to the variable '2m night time temperature';
'spatial details' correlate with the 'spatial_resolution' in the database.

sql:
SELECT MAX(version_number) AS latest_version 
FROM dataset_versions 
WHERE dataset_id = (SELECT dataset_id FROM datasets WHERE dataset_name = 'ABC');

SELECT d.dataset_name
FROM datasets d
INNER JOIN climo_data c ON d.dataset_id = c.dataset_id;
